module RefModule(
    input [3:0] A,
    input [3:0] B,
    output reg [4:0] X  // Change output type to reg
);wire [4:0] obf_sum;

    assign obf_sum = A + B;

    always @(*) begin
        if (obf_sum <= 15) begin
            X = {1'b0, obf_sum};
        end else begin
            X = obf_sum;
        end
    end

endmodule
